-- UA graduate data seed migration.
-- Idempotent import for the canonical UA graduate dataset.

DO $$
DECLARE
    v_university_id BIGINT;
BEGIN

    SELECT 'Université Antonine', NULL, 'UA', 'Lebanon', NULL, NULL, NULL, NULL, NULL
    WHERE NOT EXISTS (SELECT 1 FROM university WHERE name = 'Université Antonine');

    SELECT id INTO v_university_id FROM university WHERE name = 'Université Antonine' ORDER BY id LIMIT 1;

    ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, updated_at = NOW();

    ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, native_name = EXCLUDED.native_name;

    CREATE TEMP TABLE ua_source_seed (source_id TEXT PRIMARY KEY, title TEXT NOT NULL, url TEXT NOT NULL, source_type TEXT NOT NULL, accessed_at DATE, notes TEXT) ON COMMIT DROP;

    SELECT v_university_id, title, url, source_type, accessed_at FROM ua_source_seed
    ON CONFLICT (university_id, url) DO UPDATE SET title = EXCLUDED.title, source_type = EXCLUDED.source_type, accessed_at = EXCLUDED.accessed_at, updated_at = NOW();

    CREATE TEMP TABLE ua_faculty_seed (name TEXT PRIMARY KEY, short_name TEXT, faculty_type TEXT NOT NULL, official_url TEXT, notes TEXT) ON COMMIT DROP;

    SELECT v_university_id, name, short_name, faculty_type, official_url, notes FROM ua_faculty_seed
    ON CONFLICT (university_id, name) DO UPDATE SET short_name = EXCLUDED.short_name, faculty_type = EXCLUDED.faculty_type, official_url = EXCLUDED.official_url, notes = EXCLUDED.notes, updated_at = NOW();

    CREATE TEMP TABLE ua_program_seed (program_key TEXT PRIMARY KEY, faculty_name TEXT NOT NULL, major_category TEXT, major TEXT, degree_type TEXT NOT NULL, official_degree_name TEXT, thesis_or_non_thesis TEXT, credits INTEGER, duration_value NUMERIC(10, 2), duration_unit TEXT, primary_language_code TEXT, delivery_mode TEXT, program_description TEXT, official_program_url TEXT, notes TEXT, source_url TEXT NOT NULL) ON COMMIT DROP;

    SELECT v_university_id, f.id, NULL, dt.id, p.program_key, p.major_category, p.major, p.official_degree_name, p.thesis_or_non_thesis, p.credits, p.duration_value, p.duration_unit, l.id, p.delivery_mode, p.program_description, p.official_program_url, s.id, p.notes
    FROM ua_program_seed p
    JOIN university_faculty f ON f.university_id = v_university_id AND f.name = p.faculty_name
    LEFT JOIN degree_type dt ON dt.code = p.degree_type
    LEFT JOIN language l ON l.code = p.primary_language_code
    JOIN source s ON s.university_id = v_university_id AND s.url = p.source_url
    ON CONFLICT (university_id, program_key) DO UPDATE SET faculty_id = EXCLUDED.faculty_id, department_id = EXCLUDED.department_id, degree_type_id = EXCLUDED.degree_type_id, major_category = EXCLUDED.major_category, major = EXCLUDED.major, official_degree_name = EXCLUDED.official_degree_name, thesis_or_non_thesis = EXCLUDED.thesis_or_non_thesis, credits = EXCLUDED.credits, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, primary_language_id = EXCLUDED.primary_language_id, delivery_mode = EXCLUDED.delivery_mode, program_description = EXCLUDED.program_description, official_program_url = EXCLUDED.official_program_url, source_id = EXCLUDED.source_id, notes = EXCLUDED.notes, updated_at = NOW();

    CREATE TEMP TABLE ua_tuition_seed (program_key TEXT PRIMARY KEY, faculty_name TEXT NOT NULL, source_url TEXT NOT NULL, academic_year TEXT, currency TEXT, billing_basis TEXT, amount NUMERIC(12, 2), category TEXT, notes TEXT) ON COMMIT DROP;

    SELECT v_university_id, f.id, NULL, gp.id, 'PROGRAM', CONCAT('ua-tuition-', t.program_key), t.academic_year, t.currency, t.billing_basis, t.amount, t.category, t.notes, s.id
    FROM ua_tuition_seed t
    JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = t.program_key
    JOIN university_faculty f ON f.university_id = v_university_id AND f.name = t.faculty_name
    JOIN source s ON s.university_id = v_university_id AND s.url = t.source_url
    ON CONFLICT (university_id, record_key) DO UPDATE SET faculty_id = EXCLUDED.faculty_id, department_id = EXCLUDED.department_id, program_id = EXCLUDED.program_id, scope_level = EXCLUDED.scope_level, academic_year = EXCLUDED.academic_year, currency = EXCLUDED.currency, billing_basis = EXCLUDED.billing_basis, amount = EXCLUDED.amount, category = EXCLUDED.category, notes = EXCLUDED.notes, source_id = EXCLUDED.source_id, updated_at = NOW();

    CREATE TEMP TABLE ua_fee_seed (record_key TEXT PRIMARY KEY, fee_name TEXT NOT NULL, source_url TEXT NOT NULL, academic_year TEXT, billing_basis TEXT NOT NULL, currency TEXT NOT NULL, amount NUMERIC(12, 2), category TEXT, notes TEXT) ON COMMIT DROP;

    SELECT v_university_id, NULL, NULL, NULL, 'UNIVERSITY', f.record_key, f.academic_year, f.fee_name, f.billing_basis, f.currency, f.amount, f.category, f.notes, s.id
    FROM ua_fee_seed f
    JOIN source s ON s.university_id = v_university_id AND s.url = f.source_url
    ON CONFLICT (university_id, record_key) DO UPDATE SET academic_year = EXCLUDED.academic_year, fee_name = EXCLUDED.fee_name, billing_basis = EXCLUDED.billing_basis, currency = EXCLUDED.currency, amount = EXCLUDED.amount, category = EXCLUDED.category, notes = EXCLUDED.notes, source_id = EXCLUDED.source_id, updated_at = NOW();

    CREATE TEMP TABLE ua_admission_seed (record_key TEXT PRIMARY KEY, program_key TEXT, faculty_name TEXT, scope_level TEXT NOT NULL, requirement_type TEXT NOT NULL, requirement_text TEXT NOT NULL, comparison_operator TEXT, threshold_value NUMERIC(12, 2), threshold_unit TEXT, is_required BOOLEAN NOT NULL, notes TEXT, source_url TEXT NOT NULL) ON COMMIT DROP;

    SELECT v_university_id, CASE WHEN a.faculty_name IS NULL THEN NULL ELSE f.id END, NULL, CASE WHEN a.program_key IS NULL THEN NULL ELSE gp.id END, a.scope_level, a.record_key, a.requirement_type, a.requirement_text, a.comparison_operator, a.threshold_value, a.threshold_unit, a.is_required, a.notes, s.id
    FROM ua_admission_seed a
    LEFT JOIN university_faculty f ON f.university_id = v_university_id AND f.name = a.faculty_name
    LEFT JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = a.program_key
    JOIN source s ON s.university_id = v_university_id AND s.url = a.source_url
    ON CONFLICT (university_id, record_key) DO UPDATE SET faculty_id = EXCLUDED.faculty_id, department_id = EXCLUDED.department_id, program_id = EXCLUDED.program_id, scope_level = EXCLUDED.scope_level, requirement_type = EXCLUDED.requirement_type, requirement_text = EXCLUDED.requirement_text, comparison_operator = EXCLUDED.comparison_operator, threshold_value = EXCLUDED.threshold_value, threshold_unit = EXCLUDED.threshold_unit, is_required = EXCLUDED.is_required, notes = EXCLUDED.notes, source_id = EXCLUDED.source_id, updated_at = NOW();

    CREATE TEMP TABLE ua_document_seed (record_key TEXT PRIMARY KEY, document_type TEXT NOT NULL, document_name TEXT NOT NULL, sort_order INTEGER, notes TEXT, source_url TEXT NOT NULL) ON COMMIT DROP;

    SELECT v_university_id, NULL, NULL, NULL, 'UNIVERSITY', d.record_key, d.document_type, d.document_name, FALSE, d.sort_order, d.notes, s.id
    FROM ua_document_seed d
    JOIN source s ON s.university_id = v_university_id AND s.url = d.source_url
    ON CONFLICT (university_id, record_key) DO UPDATE SET document_type = EXCLUDED.document_type, document_name = EXCLUDED.document_name, is_optional = EXCLUDED.is_optional, sort_order = EXCLUDED.sort_order, notes = EXCLUDED.notes, source_id = EXCLUDED.source_id, updated_at = NOW();

    CREATE TEMP TABLE ua_deadline_seed (record_key TEXT PRIMARY KEY, academic_year TEXT, deadline_type TEXT NOT NULL, term TEXT, deadline_date DATE, note TEXT, source_url TEXT NOT NULL) ON COMMIT DROP;

    SELECT v_university_id, NULL, NULL, NULL, 'UNIVERSITY', d.record_key, d.academic_year, d.deadline_type, d.term, d.deadline_date, d.note, s.id
    FROM ua_deadline_seed d
    JOIN source s ON s.university_id = v_university_id AND s.url = d.source_url
    ON CONFLICT (university_id, record_key) DO UPDATE SET academic_year = EXCLUDED.academic_year, deadline_type = EXCLUDED.deadline_type, term = EXCLUDED.term, deadline_date = EXCLUDED.deadline_date, note = EXCLUDED.note, source_id = EXCLUDED.source_id, updated_at = NOW();

    CREATE TEMP TABLE ua_accreditation_seed (record_key TEXT PRIMARY KEY, program_key TEXT, faculty_name TEXT NOT NULL, name TEXT NOT NULL, authority TEXT, status TEXT, valid_from DATE, valid_until DATE, notes TEXT, source_url TEXT NOT NULL) ON COMMIT DROP;

    SELECT v_university_id, f.id, NULL, gp.id, 'PROGRAM', a.record_key, a.name, a.authority, a.status, a.valid_from, a.valid_until, a.notes, s.id
    FROM ua_accreditation_seed a
    JOIN university_faculty f ON f.university_id = v_university_id AND f.name = a.faculty_name
    JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = a.program_key
    JOIN source s ON s.university_id = v_university_id AND s.url = a.source_url
    ON CONFLICT (university_id, record_key) DO UPDATE SET faculty_id = EXCLUDED.faculty_id, program_id = EXCLUDED.program_id, name = EXCLUDED.name, authority = EXCLUDED.authority, status = EXCLUDED.status, valid_from = EXCLUDED.valid_from, valid_until = EXCLUDED.valid_until, notes = EXCLUDED.notes, source_id = EXCLUDED.source_id, updated_at = NOW();

    CREATE TEMP TABLE ua_prog_source_seed (record_key TEXT PRIMARY KEY, program_key TEXT NOT NULL, faculty_name TEXT NOT NULL, source_url TEXT NOT NULL, source_role TEXT NOT NULL, source_order INTEGER NOT NULL, evidence_text TEXT, notes TEXT) ON COMMIT DROP;

    SELECT v_university_id, gp.id, s.id, ps.source_role, ps.source_order, ps.evidence_text, ps.notes
    FROM ua_prog_source_seed ps
    JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = ps.program_key
    JOIN source s ON s.university_id = v_university_id AND s.url = ps.source_url
    ON CONFLICT (program_id, source_id, source_role) DO UPDATE SET source_order = EXCLUDED.source_order, evidence_text = EXCLUDED.evidence_text, notes = EXCLUDED.notes, updated_at = NOW();

END $$;
